const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 110;

type Item = { type: string };
type Scenario = { steps: { items: Item[] }[] };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const RUNE_BLOCK_PRICE = 60;
const RUNE_BLOCK_SIZE = 3;

const policyBaseFor = (items: Item[]): number => {
  const itemsSum = items.reduce((acc, item) => acc + BASE_PREMIUMS[item.type], 0);
  const runeCount = items.filter((item) => item.type === "rune").length;
  const formsRuneBlock = runeCount === RUNE_BLOCK_SIZE;
  const runeBlockDiscount = formsRuneBlock ? runeCount * BASE_PREMIUMS.rune - RUNE_BLOCK_PRICE : 0;
  return itemsSum - runeBlockDiscount;
};

export const runScenario = (input: unknown): unknown => {
  const items = (input as Scenario).steps[0].items;
  const policyBase = policyBaseFor(items);
  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
  return { results: [{ premium }] };
};

