    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it.todo("two runes yield 55 G (50 base + 5 fee)");
  it("three alike runes form a block at 60 G base (60 + 6 first insurance + 5 fee = 71 G)", () => {
