  it("empty item list yields premium of 5 G (just the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("a single plain sword quote yields 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("a single plain amulet quote yields 71 G (60 base + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("a single plain staff quote yields 93 G (80 base + 8 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("a single plain potion quote yields 49 G (40 base + 4 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components
  it("a single rune yields 33 G (25 base + 3 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("three alike runes form a block at 60 G base (60 + 6 first insurance + 5 fee = 71 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("four runes yield 105 G (no block — block is exactly 3)");
  it("three runes and three moonstones form two blocks: 120 G base (132 + 5 fee with surcharge = 137 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // 120 base × 1.10 = 132, + 5 fee = 137
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });
  it.todo("two runes plus one moonstone yield 75 G base (no block)");

  // Item-specific surcharges
  it("a cursed sword adds 50% curse surcharge to its base premium (165 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 10 first insurance + 5 fee = 165
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("a sword with enchantment level 5 adds 30% high-enchantment surcharge (145 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    // 100 base + 30 high-enchantment + 10 first insurance + 5 fee = 145
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("a sword with enchantment level 4 has no high-enchantment surcharge");
  it.todo("a cursed sword with enchantment 5 stacks both surcharges");

  // Policy-wide modifiers
  it("a 2-year customer receives a 20% loyalty discount on policy base", () => {
    // 100 base, 2 year loyal (20% off base = -20), +10% first insurance = 90, +5 fee = 95
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("first insurance adds 10% surcharge on policy base");
  it.todo("a follow-up contract gets a 15% discount on policy base");

  // Multi-item modifier scope
  it.todo("cursed surcharge applies only to the cursed item, not the policy total");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor");

  // Integration examples
  it.todo("newcomer with cursed sword yields 165 G");
  it.todo("long-standing customer's second contract with cursed enchantment-7 sword yields 160 G");

  // Claim — base behaviors
  it.todo("standard sword damage of 500 G yields payout 400 G (after 100 G deductible)");
  it.todo("damage to a rune (250 G insurance) with damage 200 G yields payout 100 G");
  it.todo("damage to an item with enchantment ≥ 8 is reimbursed at 50% then deductible");
  it.todo("damage to a dragon-material item is fully reimbursed then deductible");
  it.todo("dragon material + high enchantment: 50% rule wins, then deductible");
  it.todo("deductible applies once per damage entry on multi-item incidents");

  // Cap
  it.todo("payout is capped at twice the unmodified insurance sum across claims");
  it.todo("returns remainingCap after each claim");

  // Multiple items of same type
  it.todo("two swords on a policy double the insurance sum");
  it.todo("more damages of a type than insured items rejects the claim");

  // Error handling
  it.todo("quote with unknown item type rejects the scenario");
  it.todo("claim with damage on item not in policy rejects the scenario");
  it.todo("claim with negative damage amount rejects the scenario");
});

